const items = $input.all();
const oneYearAgo = $now.minus({years: 1}).toFormat('yyyy-MM-dd');

const vendorMap = {};

for (const item of items) {
  const name = item.json.name || '';
  if (!name.includes('privacy-assessment')) continue;

  const vendorMatch = name.match(/^(.+?)-privacy-assessment-(\d{4}-\d{2}-\d{2})/i);
  if (!vendorMatch) continue;

  const vendor = vendorMatch[1].toLowerCase();
  const date = vendorMatch[2];

  if (!vendorMap[vendor] || date > vendorMap[vendor]) {
    vendorMap[vendor] = date;
  }
}

const vendorFolders = $('📂 List All Vendor Folders').all();

return vendorFolders.map(folder => {
  const folderName = folder.json.name.toLowerCase();
  const mostRecent = vendorMap[folderName];
  const skipVendor = mostRecent ? mostRecent > oneYearAgo : false;

  return {
    json: {
      folderId: folder.json.id,
      vendorName: folder.json.name,
      skipVendor,
      mostRecentAssessment: mostRecent || null
    }
  };
});

