const response = $input.first().json;
const domain = response.content[0].text.trim().toLowerCase()
  .replace(/^https?:\/\//, '')
  .replace(/\/$/, '');

const vendorName = $('🔁 Loop Over Vendors').first().json.vendorName;
const folderId = $('🔁 Loop Over Vendors').first().json.folderId;

const candidates = [
  `https://www.${domain}/legal/privacy-policy`,
  `https://www.${domain}/legal/privacy`,
  `https://${domain}/legal/privacy-policy`,
  `https://${domain}/legal/privacy`,
  `https://www.${domain}/privacy-policy`,
  `https://www.${domain}/privacy`,
  `https://${domain}/privacy-policy`,
  `https://${domain}/privacy`,
  `https://www.${domain}/privacy-notice`,
  `https://www.${domain}/policies/privacy`,
  `https://www.${domain}/about/privacy`,
  `https://www.${domain}/trust/privacy`
];

return [{ json: { domain, vendorName, folderId, candidates, currentTier: 1, currentIndex: 0 } }];

const result = $input.first();
const prevData = $('🗂️ Build URL Candidates').first().json;
const responseData = result.json && result.json.data ? result.json.data : '';
const successUrl = prevData.candidates[prevData.currentIndex];

const isSubstantial = responseData.length > 5000;
const isBadPath = /(\/platform|\/product|\/solution|\/service|\/feature|\/blog|\/about\/(?!privacy)|\/resources)/i.test(successUrl);
const is404 = /<title>.*404.*<\/title>/i.test(responseData) || /error_404/.test(responseData);

const hasPrivacyContent = (
  /privacy\s+policy/i.test(responseData) &&
  (/data\s+subject|lawful\s+basis|legitimate\s+interest|data\s+controller|data\s+processor/i.test(responseData) ||
   /gdpr|ccpa|personal\s+data.*collect|we\s+collect.*personal/i.test(responseData))
);

const success = isSubstantial && !isBadPath && !is404 && hasPrivacyContent;

if (success) {
  return [{
    json: {
      ...prevData,
      policyUrl: successUrl,
      discoveryTier: 1,
      discovered: true
    }
  }];
}

const nextIndex = prevData.currentIndex + 1;
if (nextIndex < prevData.candidates.length) {
  return [{ json: { ...prevData, currentIndex: nextIndex, discovered: false } }];
}

return [{ json: { ...prevData, discovered: false, tier1Failed: true } }];

const robotsResult = $input.first();
const prevData = $('🔎 Check Tier 1 Result').first().json;

let foundUrl = null;

if (robotsResult.json && robotsResult.json.data) {
  const lines = robotsResult.json.data.split('\n');
  for (const line of lines) {
    if (line.toLowerCase().startsWith('sitemap:')) {
      const sitemapUrl = line.split(':').slice(1).join(':').trim();
      return [{ json: { ...prevData, sitemapUrl, tier2Source: 'robots' } }];
    }
  }

  const privacyMatch = robotsResult.json.data.match(/https?:\/\/[^\s]*privac[^\s]*/i);
  if (privacyMatch) {
    foundUrl = privacyMatch[0];
  }
}

if (foundUrl) {
  return [{ json: { ...prevData, policyUrl: foundUrl, discoveryTier: 2, discovered: true } }];
}

return [{ json: { ...prevData, discovered: false, tier2Failed: true } }];

const homepageResult = $input.first();
const prevData = $('🔎 Parse robots.txt for Privacy URL').first().json;

let foundUrl = null;

if (homepageResult.json && homepageResult.json.data) {
  const html = homepageResult.json.data;

  const linkRegex = /href=["']([^"']*privac[^"']*)["']/gi;
  let match;
  while ((match = linkRegex.exec(html)) !== null) {
    const href = match[1];
    if (href.startsWith('http')) {
      foundUrl = href;
    } else if (href.startsWith('/')) {
      foundUrl = `https://${prevData.domain}${href}`;
    }
    break;
  }
}

if (foundUrl) {
  return [{ json: { ...prevData, policyUrl: foundUrl, discoveryTier: 3, discovered: true } }];
}

return [{ 
  json: { 
    ...prevData, 
    discovered: false, 
    allTiersFailed: true,
    manualReviewReason: `Could not auto-discover privacy policy URL for ${prevData.vendorName}.`
  } 
}];

const policyText = $input.first().json.data;
const ctx = $input.first().json;
const vendor = ctx.vendorName;
const folderId = ctx.folderId;
const policyUrl = ctx.policyUrl;
const assessmentDate = $now.toFormat('yyyy-MM-dd');

const prompt = `You are a privacy risk analyst. Analyze the following privacy policy and score it across 8 dimensions. Return ONLY valid JSON, no other text, no markdown code fences.

SCORING RUBRIC (1-5):
1 = Missing or absent
2 = Vague or inadequate
3 = Partial - present but incomplete
4 = Good - mostly complete
5 = Strong - comprehensive and specific

DIMENSIONS TO SCORE:
D1 - Data Minimization: Are data categories specific? Are retention windows defined?
D2 - Sub-Processor Transparency: Is a named sub-processor list published? Change notification mechanism?
D3 - Data Subject Rights: Are DSAR/deletion/portability mechanisms described with timelines?
D4 - Transfer Mechanisms: Are cross-border transfer mechanisms named (SCCs, BCRs, adequacy)?
D5 - Breach Notification: Are customer notification timelines and obligations stated?
D6 - AI/ML Data Usage (weight 1.5x): Is AI/ML use disclosed? Is training opt-out available?
D7 - Retention & Deletion: Are specific retention periods and deletion procedures defined?
D8 - DPA Completeness (weight 1.5x): Does the policy include Art. 28 required elements?

WEIGHTED AVERAGE: D6 and D8 count 1.5x. Calculate weighted average.
RISK TIER: 1.0-2.0 = HIGH, 2.1-3.5 = MEDIUM, 3.6-5.0 = LOW

Return this exact JSON structure:
{
  "vendor": "<vendor name>",
  "assessment_date": "<YYYY-MM-DD>",
  "policy_url": "<url>",
  "discovery_tier": <1, 2, or 3>,
  "weighted_average": <number>,
  "risk_tier": "HIGH|MEDIUM|LOW",
  "is_ai_vendor": <true|false>,
  "ai_training_risk": <true|false>,
  "scores": {
    "D1_data_minimization": { "score": <1-5>, "rationale": "<text>", "red_flags": ["<flag1>", "<flag2>"] },
    "D2_sub_processor": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D3_subject_rights": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D4_transfer_mechanisms": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D5_breach_notification": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D6_ai_ml_usage": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D7_retention_deletion": { "score": <1-5>, "rationale": "<text>", "red_flags": [] },
    "D8_dpa_completeness": { "score": <1-5>, "rationale": "<text>", "red_flags": [] }
  },
  "top_3_findings": ["<finding1>", "<finding2>", "<finding3>"]
}

Vendor: ${vendor}
Policy URL: ${policyUrl}
Assessment Date: ${assessmentDate}

Privacy Policy Text:
${policyText}`;

return [{
  json: {
    folderId,
    vendorName: vendor,
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 4000,
      messages: [{ role: "user", content: prompt }]
    })
  }
}];

const response = $input.first().json;
const rawText = response.content[0].text;
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const assessment = JSON.parse(cleaned);

// Thread folderId and vendorName forward from Build AI Request
const folderId = $('🔧 Build AI Request').first().json.folderId;
const vendorName = $('🔧 Build AI Request').first().json.vendorName;

return [{ json: { ...assessment, folderId, vendorName } }];

const data = $json;

const riskColor = { 'HIGH': '#ff4444', 'MEDIUM': '#ffaa00', 'LOW': '#00ff88' };
const riskBg = { 'HIGH': '#2a0000', 'MEDIUM': '#2a1a00', 'LOW': '#002a1a' };

const scoreBar = (score) => '█'.repeat(score) + '░'.repeat(5 - score);
const scoreColor = (score) => {
  if (score <= 1) return '#ff4444';
  if (score <= 2) return '#ff8800';
  if (score <= 3) return '#ffdd00';
  return '#00ff88';
};

const dimensionLabels = {
  D1_data_minimization: 'D1 · DATA MINIMIZATION',
  D2_sub_processor: 'D2 · SUB-PROCESSORS',
  D3_subject_rights: 'D3 · SUBJECT RIGHTS',
  D4_transfer_mechanisms: 'D4 · TRANSFER MECHANISMS',
  D5_breach_notification: 'D5 · BREACH NOTIFICATION',
  D6_ai_ml_usage: 'D6 · AI/ML DATA USAGE ★',
  D7_retention_deletion: 'D7 · RETENTION & DELETION',
  D8_dpa_completeness: 'D8 · DPA COMPLETENESS ★'
};

const scoresHTML = Object.entries(data.scores || {}).map(([key, val]) => {
  const label = dimensionLabels[key] || key;
  const score = val.score;
  const rationale = val.rationale || '';
  const redFlags = (val.red_flags || []).map(f => `<li>⚠ ${f}</li>`).join('');
  return `
    <div class="dimension-card" style="border-color: ${scoreColor(score)}">
      <div class="dim-header">
        <span class="dim-label">${label}</span>
        <span class="dim-score" style="color: ${scoreColor(score)}">${scoreBar(score)} ${score}/5</span>
      </div>
      <div class="dim-rationale">${rationale}</div>
      ${redFlags ? `<ul class="red-flags">${redFlags}</ul>` : ''}
    </div>
  `;
}).join('');

const top3HTML = (data.top_3_findings || []).map(f => `<div class="finding">▶ ${f}</div>`).join('');

const discoveryBadge = data.discovery_tier ? `<span class="badge badge-tier">🔍 DISCOVERED VIA TIER ${data.discovery_tier}</span>` : '';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Privacy Assessment — ${data.vendor}</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&family=Share+Tech+Mono&display=swap');
  :root { --bg: #0a0a0f; --panel: #12121a; --border: #2a2a3a; --text: #c8c8e8; --dim: #6060a0; --accent: #7700ff; --risk: ${riskColor[data.risk_tier] || '#ffaa00'}; --risk-bg: ${riskBg[data.risk_tier] || '#2a1a00'}; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: var(--bg); color: var(--text); font-family: 'Share Tech Mono', monospace; font-size: 13px; line-height: 1.6; padding: 32px 24px; max-width: 900px; margin: 0 auto; }
  body::before { content: ''; position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.15) 2px, rgba(0,0,0,0.15) 4px); pointer-events: none; z-index: 999; }
  .header { text-align: center; border: 3px solid var(--accent); padding: 24px; margin-bottom: 32px; background: #0d0d18; }
  .header::before { content: '◄ THE PRIVACY LENS ►'; display: block; font-family: 'Press Start 2P', monospace; font-size: 9px; color: var(--accent); margin-bottom: 16px; letter-spacing: 2px; }
  .vendor-name { font-family: 'Press Start 2P', monospace; font-size: 18px; color: #fff; margin-bottom: 8px; text-shadow: 0 0 20px var(--accent); }
  .assessment-date { color: var(--dim); font-size: 11px; }
  .risk-banner { background: var(--risk-bg); border: 3px solid var(--risk); padding: 20px 24px; margin-bottom: 24px; display: flex; justify-content: space-between; align-items: center; }
  .risk-label { font-family: 'Press Start 2P', monospace; font-size: 10px; color: var(--dim); }
  .risk-tier { font-family: 'Press Start 2P', monospace; font-size: 22px; color: var(--risk); text-shadow: 0 0 16px var(--risk); }
  .risk-score { font-family: 'Press Start 2P', monospace; font-size: 14px; color: var(--risk); text-align: right; }
  .badges { display: flex; gap: 12px; margin-bottom: 24px; flex-wrap: wrap; }
  .badge { border: 2px solid; padding: 6px 12px; font-family: 'Press Start 2P', monospace; font-size: 8px; }
  .badge.ai { border-color: #ff00ff; color: #ff00ff; background: #1a001a; }
  .badge.no-ai { border-color: #404060; color: #404060; background: #0d0d18; }
  .badge.ai-risk { border-color: #ff4444; color: #ff4444; background: #1a0000; }
  .badge-tier { border-color: #00c8ff; color: #00c8ff; background: #001a2a; }
  .section { border: 2px solid var(--border); margin-bottom: 20px; background: var(--panel); }
  .section-header { background: var(--border); padding: 10px 16px; font-family: 'Press Start 2P', monospace; font-size: 9px; color: var(--accent); letter-spacing: 1px; }
  .section-body { padding: 16px; }
  .finding { padding: 8px 0; border-bottom: 1px solid var(--border); color: #ffcc00; font-size: 12px; }
  .finding:last-child { border-bottom: none; }
  .dimension-card { border: 2px solid; margin-bottom: 12px; background: #0d0d18; padding: 14px 16px; }
  .dim-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; flex-wrap: wrap; gap: 8px; }
  .dim-label { font-family: 'Press Start 2P', monospace; font-size: 8px; color: #aaaacc; }
  .dim-score { font-family: 'Press Start 2P', monospace; font-size: 9px; white-space: nowrap; }
  .dim-rationale { color: #8888aa; font-size: 12px; margin-bottom: 8px; }
  .red-flags { list-style: none; padding: 0; }
  .red-flags li { color: #ff6644; font-size: 11px; padding: 2px 0; }
  .footer { text-align: center; margin-top: 32px; color: var(--dim); font-size: 10px; border-top: 2px solid var(--border); padding-top: 16px; font-family: 'Press Start 2P', monospace; font-size: 7px; line-height: 2; }
  .pixel-divider { text-align: center; color: var(--accent); margin: 8px 0; font-size: 10px; letter-spacing: 4px; }
</style>
</head>
<body>
<div class="header">
  <div class="vendor-name">${data.vendor || 'UNKNOWN VENDOR'}</div>
  <div class="assessment-date">ASSESSMENT DATE: ${data.assessment_date || 'N/A'}</div>
</div>
<div class="risk-banner">
  <div><div class="risk-label">RISK TIER</div><div class="risk-tier">${data.risk_tier || 'UNKNOWN'}</div></div>
  <div style="text-align:right"><div class="risk-label">WEIGHTED AVG</div><div class="risk-score">${data.weighted_average || 'N/A'} / 5</div></div>
</div>
<div class="badges">
  ${data.is_ai_vendor ? '<div class="badge ai">⚡ AI VENDOR DETECTED</div>' : '<div class="badge no-ai">○ NOT AI VENDOR</div>'}
  ${data.ai_training_risk ? '<div class="badge ai-risk">⚠ AI TRAINING RISK</div>' : ''}
  ${discoveryBadge}
</div>
<div class="section"><div class="section-header">▶ TOP FINDINGS</div><div class="section-body">${top3HTML || '<div class="finding">No findings recorded.</div>'}</div></div>
<div class="section"><div class="section-header">▶ DIMENSION SCORES</div><div class="section-body">${scoresHTML || '<div>No scores available.</div>'}</div></div>
<div class="pixel-divider">· · · · · · · · · · · · · · · · · · · ·</div>
<div class="footer">
  GENERATED BY THE PRIVACY LENS · PHASE 2 — BATCH MODE<br>
  OPEN SOURCE TPRM AUTOMATION · github.com/conorrusso/privacy-risk-analyzer<br>
  ${new Date().toISOString()}
</div>
</body>
</html>`;

const htmlBuffer = Buffer.from(html, 'utf8');
return [{ 
  json: { vendor: data.vendor, assessment_date: data.assessment_date, risk_tier: data.risk_tier, folderId: data.folderId },
  binary: { htmlFile: { data: htmlBuffer.toString('base64'), mimeType: 'text/html', fileName: 'index.html' } }
}];

const html = $input.first().json.data || '';

// Strip all script/style tags and HTML markup to get clean policy text
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, ' ')
  .replace(/\s{3,}/g, '\n\n')
  .trim();

const ctx = $('🔗 Prepare Fetch Context').first().json;

return [{
  json: {
    data: text,
    policyUrl: ctx.policyUrl,
    vendorName: ctx.vendorName,
    folderId: ctx.folderId,
    discoveryTier: ctx.discoveryTier
  }
}];

return [{
  json: {
    policyUrl: $json.policyUrl,
    vendorName: $json.vendorName,
    folderId: $json.folderId,
    discoveryTier: $json.discoveryTier
  }
}];
